// import React from "react";
const { useEffect, useRef } = React;

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;

  const heroRef = useRef(null);

  useEffect(() => {
    const els = heroRef.current?.querySelectorAll(".anim-in");
    if (!els) return;
    els.forEach((el, i) => {
      el.style.opacity = "0";
      el.style.transform = "translateY(24px)";
      el.style.transition = `opacity 0.6s ease ${i * 0.1}s, transform 0.6s ease ${i * 0.1}s`;
      requestAnimationFrame(() => {
        setTimeout(() => {
          el.style.opacity = "1";
          el.style.transform = "translateY(0)";
        }, 60);
      });
    });
  }, []);

  return (
    <>
      <style>{`
        /* ─── Keyframes ─── */
        @keyframes pulse-ring {
          0%   { box-shadow: 0 0 0 0 rgba(0,229,255,0.5); }
          70%  { box-shadow: 0 0 0 7px rgba(0,229,255,0); }
          100% { box-shadow: 0 0 0 0 rgba(0,229,255,0); }
        }
        @keyframes blob-drift {
          0%,100% { transform: translate(0,0) scale(1); }
          33%      { transform: translate(20px,-15px) scale(1.05); }
          66%      { transform: translate(-10px,20px) scale(0.97); }
        }
        @keyframes stat-pop {
          0%   { transform: scale(0.88); opacity:0; }
          60%  { transform: scale(1.04); }
          100% { transform: scale(1);    opacity:1; }
        }

        /* ─── Layout ─── */
        .hero-section {
          min-height: 100svh;
          display: flex;
          flex-direction: column;
          justify-content: center;
          padding: clamp(80px,10vh,110px) clamp(1rem,5vw,4rem) clamp(2.5rem,5vw,5rem);
          position: relative;
          overflow: hidden;
          box-sizing: border-box;
        }
        .hero-inner {
          max-width: 860px;
          width: 100%;
          position: relative;
          z-index: 1;
        }

        /* ─── Badge ─── */
        .hero-badge {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: rgba(0,229,255,0.08);
          border: 1px solid rgba(0,229,255,0.2);
          border-radius: 99px;
          padding: 5px 14px;
          margin-bottom: 1.25rem;
        }
        .hero-badge-dot {
          width: 7px;
          height: 7px;
          border-radius: 50%;
          background: var(--accent);
          animation: pulse-ring 2s infinite;
          flex-shrink: 0;
        }
        .hero-badge-text {
          font-size: clamp(0.62rem, 1.2vw, 0.7rem);
          color: var(--accent);
          font-weight: 600;
          font-family: var(--font-display);
          letter-spacing: 0.06em;
          text-transform: uppercase;
          white-space: nowrap;
        }

        /* ─── Name ─── */
        .hero-name {
          font-family: var(--font-display);
          font-weight: 800;
          line-height: 1.05;
          letter-spacing: -0.03em;
          margin: 0 0 0.6rem;
          font-size: clamp(2rem, 6vw, 5rem);
          word-break: break-word;
          hyphens: auto;
        }
        .hero-name-gradient {
          background: linear-gradient(90deg, var(--accent), var(--accent2));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        /* ─── Sub / Tagline ─── */
        .hero-sub {
          font-family: var(--font-display);
          font-weight: 600;
          color: var(--muted);
          margin: 0 0 0.9rem;
          font-size: clamp(0.8rem, 1.6vw, 1.15rem);
          line-height: 1.5;
          flex-wrap: wrap;
          word-break: break-word;
        }
        .hero-tagline {
          font-size: clamp(0.82rem, 1.4vw, 1rem);
          color: var(--muted);
          max-width: 500px;
          line-height: 1.75;
          margin: 0 0 2rem;
        }

        /* ─── Buttons ─── */
        .hero-btns {
          display: flex;
          gap: 0.75rem;
          flex-wrap: wrap;
        }
        .btn-primary {
          background: var(--accent);
          color: #000;
          padding: 11px 24px;
          border-radius: 99px;
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.78rem, 1.1vw, 0.88rem);
          letter-spacing: 0.02em;
          transition: transform 0.2s, box-shadow 0.2s;
          display: inline-flex;
          align-items: center;
