          text-decoration: none;
          white-space: nowrap;
          cursor: pointer;
        }
        .btn-outline {
          background: transparent;
          color: var(--text);
          padding: 11px 24px;
          border-radius: 99px;
          border: 1px solid var(--border);
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.78rem, 1.1vw, 0.88rem);
          transition: border-color 0.2s, color 0.2s;
          text-decoration: none;
          white-space: nowrap;
          cursor: pointer;
        }

        /* ─── Stats bar ─── */
        .stats-wrap {
          max-width: 860px;
          width: 100%;
          position: relative;
          z-index: 1;
        }
        .stats-bar {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 1px;
          margin-top: clamp(2rem, 5vw, 3.5rem);
          background: var(--border);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          overflow: hidden;
          width: 100%;
        }
        .stat-cell {
          background: var(--surface);
          padding: clamp(0.8rem, 2vw, 1.25rem) clamp(0.4rem, 1.5vw, 1rem);
          text-align: center;
          transition: background 0.2s;
          min-width: 0;
          animation: stat-pop 0.5s ease both;
        }
        .stat-val {
          font-family: var(--font-display);
          font-size: clamp(1.1rem, 2.5vw, 2rem);
          font-weight: 800;
          color: var(--accent);
          line-height: 1;
          white-space: nowrap;
        }
        .stat-lbl {
          font-size: clamp(0.55rem, 0.9vw, 0.72rem);
          color: var(--muted);
          margin-top: 5px;
          font-weight: 500;
          line-height: 1.3;
        }

        /* ─── Background blobs ─── */
        .blob {
          position: absolute;
          border-radius: 50%;
          pointer-events: none;
          animation: blob-drift 12s ease-in-out infinite;
          will-change: transform;
        }
        .blob-1 {
          top: -10%;
          right: -5%;
          width: clamp(160px, 35vw, 480px);
          height: clamp(160px, 35vw, 480px);
          background: radial-gradient(circle, rgba(124,58,237,0.12) 0%, transparent 70%);
          animation-duration: 14s;
        }
        .blob-2 {
          bottom: 0%;
          left: -10%;
          width: clamp(120px, 28vw, 360px);
          height: clamp(120px, 28vw, 360px);
          background: radial-gradient(circle, rgba(0,229,255,0.08) 0%, transparent 70%);
          animation-duration: 10s;
          animation-delay: -4s;
        }

        /* ──────────────────────────────────────────
           BREAKPOINTS
        ────────────────────────────────────────── */

        /* Large desktop / 4K TVs: ≥ 1920px */
        @media (min-width: 1920px) {
          .hero-section {
            padding: 130px clamp(4rem, 8vw, 10rem) 6rem;
          }
          .hero-inner, .stats-wrap { max-width: 1100px; }
          .hero-name { font-size: clamp(5rem, 5.5vw, 7rem); }
          .hero-sub  { font-size: 1.35rem; }
          .hero-tagline { font-size: 1.15rem; max-width: 650px; }
          .btn-primary, .btn-outline { font-size: 1rem; padding: 14px 32px; }
          .stat-val  { font-size: 2.4rem; }
          .stat-lbl  { font-size: 0.85rem; }
          .stats-bar { grid-template-columns: repeat(4,1fr); }
        }

        /* Wide / large laptop: 1280–1919 — default styles cover this */

        /* Tablet landscape: 1024–1279 */
        @media (max-width: 1279px) and (min-width: 1025px) {
          .hero-name { font-size: clamp(2.6rem, 5vw, 4rem); }
          .hero-section { padding: 90px clamp(1.5rem, 4vw, 3rem) 3rem; }
        }

        /* Tablet portrait / small laptop: 768–1024 */
        @media (max-width: 1024px) {
          .hero-name { font-size: clamp(2.4rem, 6.5vw, 3.8rem); }
          .hero-section { padding: 90px clamp(1.25rem, 4vw, 2.5rem) 3rem; }
        }

        /* Large mobile / small tablet: 540–767 */
        @media (max-width: 767px) {
          .hero-name { font-size: clamp(2.1rem, 8vw, 3.2rem); }
          .hero-section { padding: 80px 1.5rem 2.5rem; }
          .stats-bar { grid-template-columns: repeat(2, 1fr); }
        }

        /* Standard mobile: 400–539 */
        @media (max-width: 539px) {
          .hero-section {
            padding: 76px 1.25rem 2.5rem;
            min-height: auto;
          }
          .hero-name { font-size: clamp(1.9rem, 9.5vw, 2.8rem); line-height: 1.1; }
          .hero-btns { flex-direction: column; }
          .btn-primary, .btn-outline {
            width: 100%;
            justify-content: center;
            font-size: 0.875rem;
            padding: 13px 20px;
          }
          .stats-bar { grid-template-columns: repeat(2, 1fr); }
          .stat-val  { font-size: 1.35rem; }
          .stat-lbl  { font-size: 0.6rem; }
        }

        /* iPhone SE / very small: 320–399 */
        @media (max-width: 399px) {
          .hero-section { padding: 72px 1rem 2rem; }
          .hero-name { font-size: clamp(1.7rem, 10vw, 2.2rem); }
          .hero-sub  { font-size: 0.76rem; }
          .hero-tagline { font-size: 0.8rem; }
          .hero-badge-text { font-size: 0.58rem; }
        }

        /* Galaxy Fold / tiny: < 320px */
        @media (max-width: 319px) {
          .hero-section { padding: 68px 0.85rem 1.75rem; }
          .hero-name { font-size: 1.55rem; }
          .stats-bar { grid-template-columns: 1fr 1fr; }
          .stat-val  { font-size: 1.1rem; }
        }

        /* Landscape orientation on small phones */
        @media (max-height: 500px) and (max-width: 900px) {
          .hero-section {
            min-height: auto;
            padding-top: 70px;
            padding-bottom: 1.5rem;
          }
          .hero-name { font-size: clamp(1.6rem, 5vw, 2.4rem); }
          .hero-tagline { display: none; }
          .stats-bar { margin-top: 1.25rem; }
        }

        /* Large touch devices — iPad Pro 12.9 */
        @media (min-width: 1024px) and (max-width: 1366px) and (orientation: portrait) {
          .hero-name { font-size: clamp(3rem, 7vw, 4.5rem); }
          .hero-section { padding-top: 110px; }
          .stats-bar { grid-template-columns: repeat(4, 1fr); }
        }
      `}</style>

      <section className="hero-section" id="about" ref={heroRef}>
        {/* Animated BG blobs */}
        <div className="blob blob-1" />
        <div className="blob blob-2" />

        <div className="hero-inner">
          {/* Badge */}
          <div className="hero-badge anim-in">
            <span className="hero-badge-dot" />
            <span className="hero-badge-text">Open to Opportunities</span>
          </div>

          {/* Name */}
          <h1 className="hero-name anim-in">
            {name.split(" ")[0]}{" "}
            <span className="hero-name-gradient">{name.split(" ")[1]}</span>
          </h1>

          {/* Subtitle */}
          <p className="hero-sub anim-in">
            {title} · <span style={{ color: "var(--accent3)" }}>{subtitle}</span>
          </p>

          {/* Tagline */}
          <p className="hero-tagline anim-in">{tagline}</p>

          {/* CTAs */}
          <div className="hero-btns anim-in">
            <a
              href="mailto:chavanak870@gmail.com"
              className="btn-primary"
              onMouseEnter={e => {
                e.currentTarget.style.transform = "translateY(-2px)";
                e.currentTarget.style.boxShadow = "0 8px 28px rgba(0,229,255,0.3)";
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = "none";
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              ✉ Get in Touch
            </a>
            <a
              href={`https://${contact.linkedin}`}
              target="_blank"
              rel="noreferrer"
              className="btn-outline"
              onMouseEnter={e => {
                e.currentTarget.style.borderColor = "var(--accent2)";
                e.currentTarget.style.color = "var(--accent2)";
              }}
              onMouseLeave={e => {
                e.currentTarget.style.borderColor = "var(--border)";
                e.currentTarget.style.color = "var(--text)";
              }}
            >
              in LinkedIn
            </a>
          </div>
        </div>

        {/* Stats bar */}
        <div className="stats-wrap anim-in">
          <div className="stats-bar">
            {stats.map((s, i) => (
              <div
                key={i}
                className="stat-cell"
                style={{ animationDelay: `${0.35 + i * 0.08}s` }}
                onMouseEnter={e => (e.currentTarget.style.background = "var(--surface2)")}
                onMouseLeave={e => (e.currentTarget.style.background = "var(--surface)")}
              >
                <div className="stat-val">{s.value}</div>
                <div className="stat-lbl">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
}
